DROP TABLE IF EXISTS `community_post`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `community_post` (
  `post_id` int NOT NULL AUTO_INCREMENT COMMENT '帖子编号',
  `user_id` int NOT NULL COMMENT '用户编号',
  `title` varchar(100) DEFAULT NULL COMMENT '标题',
  `content` text COMMENT '正文',
  `img_list` varchar(500) DEFAULT NULL COMMENT '图片列表(JSON)',
  `like_count` int DEFAULT '0' COMMENT '点赞数',
  `comment_count` int DEFAULT '0' COMMENT '评论数',
  `audit_status` varchar(20) NOT NULL DEFAULT '待审核' COMMENT '审核状态',
  `deleted` int NOT NULL DEFAULT '0' COMMENT '删除标记',
  `create_time` datetime DEFAULT NULL COMMENT '发布时间',
  `update_time` datetime DEFAULT NULL COMMENT '更新时间',
  PRIMARY KEY (`post_id`),
  KEY `idx_user` (`user_id`),
  KEY `idx_audit` (`audit_status`),
  KEY `idx_post_audit_deleted` (`audit_status`,`deleted`),
  KEY `idx_post_create_time` (`create_time`),
  CONSTRAINT `fk_post_user` FOREIGN KEY (`user_id`) REFERENCES `sys_user` (`user_id`) ON DELETE RESTRICT ON UPDATE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=48 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='社区帖子表';
/*!40101 SET character_set_client = @saved_cs_client */;

