INSERT INTO `community_post` VALUES (30,106,'用临期食品做了一顿丰盛的周末大餐','周末用平台食材做了一桌子菜，花了不到100块！味道和新鲜的没什么两样！#临期食品##省钱美食#','/images/community/001.jpg',433,59,'已通过',0,'2026-04-05 21:26:58','2026-04-18 02:47:47'),(31,107,'分享我的临期食品购物经验','作为三高人群，平台上有适合我们的临期食品。无糖酸奶、高纤维燕麦、低钠调味品...品质很好。','/images/community/002.jpg',141,140,'已通过',0,'2026-03-24 21:26:58','2026-04-18 02:37:43'),(32,108,'宿舍党必看！这些临期食品简直是救星','在宿舍不方便做饭，自热火锅、速食面、能量棒...便宜又方便，考试周全靠这些续命！','/images/community/003.jpg',160,45,'已通过',0,'2026-04-09 21:26:58','2026-04-18 02:48:31'),(33,109,'健身3个月，我的饮食计划分享','健身3个月，临期鸡胸肉、鸡蛋、燕麦片帮了大忙，价格比正期便宜很多，营养完全没问题。#健身打卡#','/images/community/004.jpg',700,85,'已通过',0,'2026-03-29 21:26:58','2026-04-17 18:53:18'),(34,110,'给孩子买的临期食品到了，品质超预期','买了临期牛奶和鸡蛋，收到后很惊喜！保质期还有一段时间，品质和超市的一样好。','/images/community/005.jpg',128,61,'已通过',0,'2026-03-30 21:26:58','2026-04-17 18:53:18'),(35,111,'老年人也爱上的临期食品平台','给爸妈介绍了这个平台，临期食品不仅便宜，大米、调味品放久了品质也很稳定。','/images/community/006.jpg',295,43,'已通过',0,'2026-03-24 21:26:58','2026-04-17 18:53:18'),(36,112,'零食控的快乐源泉！临期零食大测评','测评了平台上20+款临期零食，价格便宜味道好。一次别买太多就行。','/images/community/007.jpg',779,130,'已通过',0,'2026-03-27 21:26:58','2026-04-17 18:53:18'),(37,113,'用临期食材开了个小型美食party','用平台的临期食材准备了一桌菜，番茄牛腩、清蒸鱼、蔬菜沙拉...朋友们都说好吃。','/images/community/008.jpg',274,81,'已通过',0,'2026-04-03 21:26:58','2026-04-17 18:53:18'),(38,114,'程序员加班必备：临期食品续命清单','996打工人，深夜全靠食物续命。自热火锅、速食面、能量饮料便宜又方便！#程序员#','/images/community/009.jpg',777,146,'已通过',0,'2026-04-02 21:26:58','2026-04-17 18:53:18'),(39,115,'素食主义者眼中的临期食品平台','非常认可这个平台的理念。减少食物浪费从我做起，有机蔬菜、水果、豆制品种类丰富价格实惠。','/images/community/010.jpg',481,60,'已通过',0,'2026-04-03 21:26:58','2026-04-17 18:53:18'),(40,2,'分享我的临期食品购物清单，好东西一起用','整理了常买的临期食品清单：牛奶、酸奶、土豆、鸡蛋、燕麦片...都是高性价比好物！','/images/community/011.jpg',532,128,'已通过',0,'2026-03-23 21:26:58','2026-04-17 18:53:18'),(41,100,'临期食品vs正期食品：真实对比测评','买了同款临期版和正期版做了详细对比。结果发现口感营养几乎没差别，就价格差很多。','/images/community/012.jpg',471,73,'已通过',0,'2026-03-26 21:26:58','2026-04-17 18:53:18'),(42,101,'家庭主妇的临期食品厨房日记','每周日采购一次，一家人的食材基本够用了。省下来的钱给孩子报了兴趣班。','/images/community/013.jpg',744,132,'已通过',0,'2026-03-31 21:26:58','2026-04-17 18:53:18'),(43,102,'健身达人的临期食品推荐清单','作为健身教练，推荐学员买临期鸡胸肉、鱼虾、鸡蛋。高蛋白价格便宜营养没问题。','/images/community/014.jpg',721,143,'已通过',0,'2026-03-23 21:26:58','2026-04-17 18:53:18'),(44,103,'学生党一个月临期食品开销大公开','这个月在平台上总共花了280元！包含牛奶、鸡蛋、面包、水果、速食。比超市省了将近一半！','/images/community/015.jpg',316,72,'已通过',0,'2026-04-07 21:26:58','2026-04-18 02:41:53'),(45,104,'新手妈妈的安全食品选择心得','平台上临期食品虽然便宜但品质一点都不马虎。买了婴儿酸奶和溶豆，宝宝很喜欢。','/images/community/016.jpg',180,110,'已通过',0,'2026-04-06 21:26:58','2026-04-17 18:53:18');
