--
-- Table structure for table `food`
--

DROP TABLE IF EXISTS `food`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `food` (
  `food_id` int NOT NULL AUTO_INCREMENT COMMENT '食品编号',
  `merchant_id` int DEFAULT NULL COMMENT '门店编号',
  `category_id` int DEFAULT NULL COMMENT '分类编号',
  `food_name` varchar(100) NOT NULL COMMENT '食品名称',
  `origin_price` decimal(10,2) DEFAULT NULL COMMENT '原价',
  `discount_price` decimal(10,2) DEFAULT NULL COMMENT '折扣价',
  `stock_qty` int DEFAULT '0' COMMENT '库存数量',
  `expire_date` datetime DEFAULT NULL COMMENT '保质截止日期',
  `nutrition_desc` varchar(500) DEFAULT NULL COMMENT '营养说明',
  `suitable_people` varchar(255) DEFAULT NULL COMMENT '适宜人群',
  `allergen_info` varchar(255) DEFAULT NULL COMMENT '过敏原信息',
  `taste_desc` varchar(255) DEFAULT NULL COMMENT '味道特征: 酸/甜/苦/辣/咸/鲜',
  `cover_img` text,
  `description` varchar(500) DEFAULT NULL COMMENT '商品描述',
  `status` int NOT NULL DEFAULT '1' COMMENT '状态: 0-下架, 1-上架',
  `deleted` int NOT NULL DEFAULT '0' COMMENT '删除标记',
  `version` int NOT NULL DEFAULT '0' COMMENT '涔愯?閿佺増鏈?彿',
  `create_time` datetime DEFAULT NULL COMMENT '创建时间',
  `update_time` datetime DEFAULT NULL COMMENT '更新时间',
  PRIMARY KEY (`food_id`),
  KEY `idx_category` (`category_id`),
  KEY `idx_merchant` (`merchant_id`),
  KEY `idx_status` (`status`),
  KEY `idx_expire` (`expire_date`),
  KEY `idx_food_status_deleted` (`status`,`deleted`),
  KEY `idx_food_expire` (`expire_date`,`status`,`deleted`),
  CONSTRAINT `fk_food_category` FOREIGN KEY (`category_id`) REFERENCES `food_category` (`category_id`) ON DELETE SET NULL ON UPDATE CASCADE,
  CONSTRAINT `fk_food_merchant` FOREIGN KEY (`merchant_id`) REFERENCES `food_merchant` (`merchant_id`) ON DELETE SET NULL ON UPDATE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=225 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='临期食品表';
/*!40101 SET character_set_client = @saved_cs_client */;

