DROP TABLE IF EXISTS `food_after_sale`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `food_after_sale` (
  `after_sale_id` int NOT NULL AUTO_INCREMENT COMMENT '申诉编号',
  `order_id` int NOT NULL COMMENT '订单编号',
  `user_id` int NOT NULL COMMENT '用户编号',
  `reason_type` varchar(50) DEFAULT NULL COMMENT '申诉类型',
  `reason_desc` varchar(500) DEFAULT NULL COMMENT '申诉原因',
  `evidence_img` varchar(255) DEFAULT NULL COMMENT '凭证图片',
  `handle_status` varchar(20) NOT NULL COMMENT '处理状态',
  `handle_result` varchar(255) DEFAULT NULL COMMENT '处理结果',
  `apply_time` datetime DEFAULT NULL COMMENT '申请时间',
  `handle_time` datetime DEFAULT NULL COMMENT '处理时间',
  `update_time` datetime DEFAULT NULL COMMENT '更新时间',
  PRIMARY KEY (`after_sale_id`),
  KEY `idx_order` (`order_id`),
  KEY `idx_user` (`user_id`),
  KEY `idx_status` (`handle_status`),
  KEY `idx_aftersale_status` (`handle_status`),
  CONSTRAINT `fk_aftersale_order` FOREIGN KEY (`order_id`) REFERENCES `food_order` (`order_id`) ON DELETE RESTRICT ON UPDATE CASCADE,
  CONSTRAINT `fk_aftersale_user` FOREIGN KEY (`user_id`) REFERENCES `sys_user` (`user_id`) ON DELETE RESTRICT ON UPDATE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=7 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='售后申诉表';
/*!40101 SET character_set_client = @saved_cs_client */;

