INSERT INTO `food_after_sale` VALUES (1,1,4,'配送延迟','订单预计18:00送达，实际19:30才收到，等待时间过长。','https://images.unsplash.com/photo-1542838132-92c53300491e?w=400&h=300&fit=crop','待处理',NULL,'2026-04-06 19:35:00',NULL,NULL),(2,1,4,'商品破损','收到商品时包装破损，坚果有漏气，味道也不对。','https://images.unsplash.com/photo-1556742049-0cfed4f6a45d?w=400&h=300&fit=crop','待处理',NULL,'2026-04-06 20:00:00',NULL,NULL),(3,1,2,'质量问题','牛奶有明显结块现象，怀疑已变质，不敢食用。','https://images.unsplash.com/photo-1563636619-e9143da7973b?w=400&h=300&fit=crop','已通过','已为用户退款并补偿10元优惠券','2026-04-05 14:20:00','2026-04-05 16:30:00',NULL),(4,1,3,'其他','收到的商品与描述不符，实物与图片差距较大。','https://images.unsplash.com/photo-1583511655857-d19b40a7a54e?w=400&h=300&fit=crop','已驳回','经核实商品与描述一致，驳回申诉','2026-04-04 11:00:00','2026-04-04 13:00:00',NULL),(5,1,5,'配送延迟','等了三个小时才到，错过饭点，食品都不新鲜了。','https://images.unsplash.com/photo-1494423132534-1866fb9b653b?w=400&h=300&fit=crop','已通过',NULL,'2026-04-06 21:00:00','2026-04-07 09:33:43',NULL),(6,10,11,'商品不符','发错货了吧',NULL,'待处理',NULL,'2026-04-07 22:16:15',NULL,NULL);
