DROP TABLE IF EXISTS `food_article`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `food_article` (
  `article_id` int NOT NULL AUTO_INCREMENT COMMENT '文章编号',
  `title` varchar(100) NOT NULL COMMENT '标题',
  `summary` varchar(300) DEFAULT NULL COMMENT '摘要',
  `content` text COMMENT '正文内容',
  `cover_img` varchar(255) DEFAULT NULL COMMENT '封面图',
  `publisher_id` int DEFAULT NULL COMMENT '发布者编号',
  `read_count` int DEFAULT '0' COMMENT '浏览量',
  `status` int NOT NULL DEFAULT '1' COMMENT '状态',
  `deleted` int NOT NULL DEFAULT '0' COMMENT '删除标记',
  `publish_time` datetime DEFAULT NULL COMMENT '发布时间',
  PRIMARY KEY (`article_id`),
  KEY `idx_status` (`status`),
  KEY `fk_article_publisher` (`publisher_id`),
  CONSTRAINT `fk_article_publisher` FOREIGN KEY (`publisher_id`) REFERENCES `sys_user` (`user_id`) ON DELETE SET NULL ON UPDATE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=43 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='膳食百科表';
