/*!40000 ALTER TABLE `food_article` DISABLE KEYS */;
INSERT INTO `food_article` VALUES (20,'如何读懂食品标签？','学会看食品标签，做明智的消费者','购买食品时，食品标签是关键。要关注：1.生产日期和保质期 2.配料表（按含量从高到低排列）3.营养成分表 4.储存条件 5.致敏物质提示。学会看标签能帮助您做出更明智的选择。','/images/articles/001.jpg',1,1760,1,0,'2026-04-04 21:26:58'),(21,'临期不等于过期，这些误区要避免','科学认知临期食品','很多人对临期食品存在误解。误区一：临期就是过期。临期食品是指即将到达保质期但仍在保质期内。误区二：临期食品没有营养。食品在保质期内营养成分基本稳定。误区三：所有临期食品都能买。需要检查储存条件是否得当。','/images/articles/002.jpg',1,4511,1,0,'2026-03-27 21:26:58'),(22,'减少食物浪费的10个小技巧','从我做起，珍惜粮食','1.按需购买不贪多 2.先进先出 3.合理储存 4.利用边角料 5.冷冻保存 6.关注保质期 7.计划性采购 8.小份分装 9.剩菜巧利用 10.定期整理冰箱。减少食物浪费从日常细节做起。','/images/articles/003.jpg',1,4973,1,0,'2026-03-11 21:26:58'),(23,'超市临期食品专区省钱攻略','临期食品购物指南','超市临期专区省钱攻略：1.乳制品、面包、饼干适合买临期 2.生鲜肉类要谨慎 3.检查包装是否完好 4.折扣规律：距保质期越近折扣越大 5.选择正规渠道很重要。','/images/articles/004.jpg',1,2964,1,0,'2026-04-09 21:26:58'),(24,'老年人饮食指南：这样吃更健康','老年人的营养与饮食','老年人饮食重点：1.蛋白质要充足（每公斤体重1.0-1.2g）2.钙和维生素D不可少 3.少盐少油 4.多喝水 5.软烂易消化。合理膳食让老年生活更健康。','/images/articles/005.jpg',1,4715,1,0,'2026-04-02 21:26:58'),(25,'健身减脂期这样吃才能瘦','减脂饮食完全指南','减脂核心是热量缺口。关键原则：1.保证蛋白质摄入（每公斤1.6-2.2g）2.选择优质碳水（燕麦、糙米、紫薯）3.多吃蔬菜 4.健康脂肪不可少 5.少食多餐 6.多喝水2000-3000ml。','/images/articles/006.jpg',1,4946,1,0,'2026-03-29 21:26:58'),(26,'学生党营养早餐攻略','5分钟搞定健康早餐','快速早餐方案：1.隔夜燕麦杯 2.三明治（两片面包+煎蛋+生菜）3.香蕉花生酱吐司 4.即食鸡胸肉+牛奶 5.能量棒+坚果。早餐提供全天25-30%能量，不吃早餐容易暴饮暴食。','/images/articles/007.jpg',1,4315,1,0,'2026-04-07 21:26:58'),(27,'上班族午餐怎么吃才健康','工作日的营养午餐指南','上班族午餐建议：1.避免单一主食 2.外卖选清炒、蒸煮类 3.带饭族提前准备 4.控制主食量（1小碗约100g）5.少喝含糖饮料 6.饭后散步15-20分钟。健康午餐让下午更高效。','/images/articles/008.jpg',1,3832,1,0,'2026-03-19 21:26:58');
/*!40000 ALTER TABLE `food_article` ENABLE KEYS */;
UNLOCK TABLES;

