  KEY `fk_recipe_publisher` (`publisher_id`),
  CONSTRAINT `fk_recipe_publisher` FOREIGN KEY (`publisher_id`) REFERENCES `sys_user` (`user_id`) ON DELETE SET NULL ON UPDATE CASCADE
