INSERT INTO `food_recipe` VALUES (25,'蒜蓉蒸粉丝蒸扇贝','海鲜鲜美，宴客必备','食材：扇贝6个、粉丝50g、蒜末、小米辣、生抽。做法：1.扇贝洗净，粉丝泡软铺底。2.蒜末小米辣铺在扇贝上，淋生抽。3.大火蒸8分钟即可。','海鲜爱好者','/images/recipes/001.jpg',1,520,1,0,'2026-03-29 21:26:58'),(26,'可乐鸡翅','甜咸可口，孩子最爱','食材：鸡翅中8个、可乐330ml、生抽、老抽。做法：1.鸡翅焯水去腥。2.热油煎至两面金黄。3.加可乐没过鸡翅，炖30分钟即可。','儿童、家庭','/images/recipes/002.jpg',1,518,1,0,'2026-03-20 21:26:58'),(27,'糖醋里脊','酸甜开胃，外酥里嫩','食材：猪里脊300g、淀粉、番茄酱、醋、糖。做法：1.里脊切条裹淀粉炸至金黄。2.调糖醋汁。3.热油炒糖醋汁至浓稠，放里脊翻炒即可。','儿童、喜甜人群','/images/recipes/003.jpg',1,535,1,0,'2026-03-23 21:26:58'),(28,'红烧狮子头','淮扬名菜，肉香四溢','食材：猪肉馅500g、马蹄4个、蛋液、生抽、老抽。做法：1.肉馅加马蹄碎、蛋液搅拌上劲。2.做成大丸子，油炸定型。3.砂锅炖1小时即可。','所有人群','/images/recipes/004.jpg',1,369,1,0,'2026-03-12 21:26:58'),(29,'银耳红枣汤','美容养颜，滋补佳品','食材：银耳20g，红枣8颗、枸杞10g、冰糖30g。做法：1.银耳泡发撕小朵。2.所有食材加水炖1小时。3.放冰糖再炖10分钟即可。','女性、养生人群','/images/recipes/005.jpg',1,212,1,0,'2026-04-03 21:26:58'),(30,'虾仁蒸蛋','嫩滑可口，婴儿辅食','食材：鸡蛋3个、虾仁6个、温水、盐。做法：1.鸡蛋打散加1.5倍温水。2.放虾仁，盖保鲜膜扎孔。3.蒸10分钟，淋生抽香油即可。','儿童、老人','/images/recipes/006.jpg',1,470,1,0,'2026-03-20 21:26:58'),(31,'紫菜蛋花汤','简单快手，补碘佳品','食材：紫菜10g、鸡蛋2个、虾皮、盐、香油。做法：1.水烧开放紫菜和虾皮。2.蛋液慢慢淋入形成蛋花。3.加盐调味，淋香油即可。','所有人群','/images/recipes/007.jpg',1,546,1,0,'2026-04-05 21:26:58'),(32,'蒜泥白肉','川味经典，蒜香浓郁','食材：五花肉300g、黄瓜1根、蒜泥、生抽、醋、辣椒油。做法：1.五花肉整块煮熟切片。2.黄瓜切丝铺盘底，肉片铺上面。3.调蒜泥蘸汁即可。','所有人群','/images/recipes/008.jpg',1,55,1,0,'2026-03-12 21:26:58'),(33,'鱼香肉丝','川菜经典，酸甜咸辣','食材：猪里脊200g、木耳、胡萝卜、豆瓣酱。做法：1.肉丝切好加淀粉腌制。2.调鱼香汁。3.热油滑炒肉丝盛出。4.炒豆瓣酱，放配菜，放肉丝，淋鱼香汁即可。','所有人群','/images/recipes/009.jpg',1,585,1,0,'2026-03-29 21:26:58'),(34,'清炒时蔬','简单快手，营养均衡','食材：时令蔬菜300g、蒜末、盐。做法：1.蔬菜洗净切段。2.热油爆香蒜末。3.放蔬菜大火快炒至断生，加盐调味即可。','所有人群','/images/recipes/010.jpg',1,468,1,0,'2026-03-18 21:26:58'),(35,'芝士焗番茄','西式风味，奶香浓郁','食材：番茄2个、马苏里拉芝士50g、面包糠。做法：1.番茄切半去籽。2.撒芝士碎和面包糠。3.烤箱200度烤10分钟至芝士金黄即可。','年轻人、西餐爱好者','/images/recipes/011.jpg',1,88,1,0,'2026-03-15 21:26:58'),(36,'番茄牛腩煲','番茄酸甜，牛腩软烂','食材：牛腩500g、番茄3个、土豆1个。做法：1.牛腩切块焯水。2.番茄炒出汁。3.牛腩和番茄一起炖1小时，放土豆再炖30分钟即可。','所有人群','/images/recipes/012.jpg',1,226,1,0,'2026-03-20 21:26:58');
/*!40000 ALTER TABLE `food_recipe` ENABLE KEYS */;
UNLOCK TABLES;

