INSERT INTO `sys_notice` VALUES (1,'系统上线公告','城市临期食品分发系统正式上线，感谢您的使用！系统致力于减少食品浪费，为您提供优质的临期食品资源。',1,1,0,'2026-04-01 08:00:00'),(2,'积分规则更新通知','即日起，每日签到可获得10积分，订单完成后可获得订单金额等额积分（100积分=1元）。',1,1,0,'2026-04-03 10:00:00'),(3,'五一假期配送安排','五一假期期间（5月1日-5月5日），配送服务正常运营，感谢您的支持！',1,1,0,'2026-04-28 09:00:00'),(4,'食品安全知识普及','我们致力于为您提供安全优质的临期食品。所有食品均经过严格质量检测，确保在保质期内安全食用。感谢您的信任与支持！',1,1,0,'2026-03-11 21:11:43'),(5,'会员积分体系升级公告','会员积分体系全面升级！购物返积分、签到得积分、分享获积分，多种方式轻松攒积分，积分可兑换丰富礼品。',1,1,0,'2026-03-26 21:11:43'),(6,'平台服务优化通知','平台已完成服务优化，配送速度提升，推荐算法更精准，售后服务更贴心。欢迎提出宝贵意见！',1,1,0,'2026-03-31 21:11:43');
/*!40000 ALTER TABLE `sys_notice` ENABLE KEYS */;
UNLOCK TABLES;

