--
-- Table structure for table `user_behavior`
--

DROP TABLE IF EXISTS `user_behavior`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `user_behavior` (
  `behavior_id` int NOT NULL AUTO_INCREMENT COMMENT '行为编号',
  `user_id` int NOT NULL COMMENT '用户编号',
  `target_type` varchar(20) NOT NULL COMMENT '目标类型: food/article/recipe',
  `target_id` int NOT NULL COMMENT '目标编号',
  `behavior_type` varchar(20) NOT NULL COMMENT '行为类型: view/favorite/like/purchase/comment',
  `weight_score` decimal(8,2) DEFAULT NULL COMMENT '行为权重',
  `create_time` datetime DEFAULT NULL COMMENT '行为时间',
  `update_time` datetime DEFAULT NULL COMMENT '更新时间',
  PRIMARY KEY (`behavior_id`),
  KEY `idx_user` (`user_id`),
  KEY `idx_target` (`target_type`,`target_id`),
  KEY `idx_type` (`behavior_type`),
  KEY `idx_behavior_user_type_time` (`user_id`,`target_type`,`create_time`),
  KEY `idx_user_behavior_create` (`create_time`),
  CONSTRAINT `fk_behavior_user` FOREIGN KEY (`user_id`) REFERENCES `sys_user` (`user_id`) ON DELETE CASCADE ON UPDATE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=10799 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='用户行为记录表';
/*!40101 SET character_set_client = @saved_cs_client */;

